orders = [
    {'customer': 'Alice', 'amount': 100},
    {'customer': 'Alice', 'amount': 200},
    {'customer': 'Alice', 'amount': 150},
    {'customer': 'Alice', 'amount': 300},
    {'customer': 'Bob', 'amount': 250},
    {'customer': 'Bob', 'amount': 175},
    {'customer': 'Charlie', 'amount': 400},
    {'customer': 'Diana', 'amount': 120},
    {'customer': 'Diana', 'amount': 180},
    {'customer': 'Diana', 'amount': 220},
]

# CTE 1: customer_orders
customer_orders = {}
for o in orders:
    c = o['customer']
    if c not in customer_orders:
        customer_orders[c] = {'count': 0, 'total': 0}
    customer_orders[c]['count'] += 1
    customer_orders[c]['total'] += o['amount']

print("Step 1 - customer_orders:")
for cust in sorted(customer_orders):
    data = customer_orders[cust]
    print(f"  {cust}: {data['count']} orders, ${data['total']}")

# CTE 2: customer_segments
print("\nStep 2 - customer_segments:")
segments = {}
for cust, data in sorted(customer_orders.items()):
    count = data['count']
    if count > 3:
        seg = 'High'
    elif count >= 2:
        seg = 'Medium'
    else:
        seg = 'Low'
    segments[cust] = seg
    print(f"  {cust}: {seg}")

# CTE 3: segment_counts
print("\nStep 3 - segment_counts:")
seg_counts = {}
for seg in segments.values():
    seg_counts[seg] = seg_counts.get(seg, 0) + 1
for seg in ['High', 'Medium', 'Low']:
    print(f"  {seg}: {seg_counts.get(seg, 0)} customers")
